import React from "react";
import { useParams } from "react-router";
import Casts from "./Casts";

function CastsPage() {
  const { type, id, title } = useParams();

  return (
    <div className="castsPage all_movies_holder">
      <h1>catst of {title}</h1>
      <div className="inner_all_movies_holder">
        <Casts type={type} id={id} />
      </div>
    </div>
  );
}

export default CastsPage;
