import React from "react";

function WatchEpisode({ currentWatchNow }) {
  const { season, id, episode } = currentWatchNow;
  const embidLink = `https://autoembed.xyz/tv/tmdb/${id}-${season}-${episode}`;

  return (
    <div className="watchEpisodeHolder">
      <iframe
        src={embidLink}
        width="100%"
        height="100%"
        frameborder="0"
        allowfullscreen
        id="watchIframe"
        allowFullScreen="true"
        webkitallowfullscreen="true"
        mozallowfullscreen="true"
        title={episode}
      />
    </div>
  );
}

export default WatchEpisode;
